import json

top_5_businesses = locals()['var_function-call-4524421853268768571']

results_list = []
for business in top_5_businesses:
    try:
        hours_list = json.loads(business['hours'])
        hours_str_parts = []
        for day, time_range in hours_list:
            hours_str_parts.append(day + ': ' + time_range)
        hours_str = ', '.join(hours_str_parts)
    except (json.JSONDecodeError, TypeError):
        hours_str = 'N/A'

    results_list.append({
        'name': business['name'],
        'operating_hours': hours_str,
        'average_rating': round(business['average_rating'], 2)
    })

final_answer_json = {
    'title': 'Top 5 businesses open after 6:00 PM on at least one weekday, by average rating:',
    'businesses': results_list
}

print('__RESULT__:')
print(json.dumps(final_answer_json))

